import React, { useState } from "react";
import TreeView from "./TreeView";
import CategoryView from "./CategoryView";

const EditorialFlow: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'tree' | 'category'>('tree');
  const [searchTerm, setSearchTerm] = useState("");
  const [dateFilter, setDateFilter] = useState("Tous");

  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow flex-1 overflow-hidden border border-gray-200 dark:border-gray-700">
      {/* Onglets */}
      <div className="bg-gray-50 dark:bg-gray-700/50 px-6 py-4 border-b border-gray-200 dark:border-gray-700">
        <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4">
          <div className="flex gap-4">
            <button
              onClick={() => setActiveTab('tree')}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 flex items-center gap-2 ${
                activeTab === 'tree'
                  ? 'bg-purple-600 text-white shadow-lg'
                  : 'bg-gray-200 dark:bg-gray-600 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-500'
              }`}
            >
              <i className="fas fa-sitemap"></i>
              Arborescence
            </button>
            <button
              onClick={() => setActiveTab('category')}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 flex items-center gap-2 ${
                activeTab === 'category'
                  ? 'bg-purple-600 text-white shadow-lg'
                  : 'bg-gray-200 dark:bg-gray-600 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-500'
              }`}
            >
              <i className="fas fa-folder"></i>
              Par Rubriques
            </button>
          </div>
          
          {/* ✅ FILTRES DU FLUX */}
          <div className="flex gap-3 flex-wrap">
            <div className="relative">
              <input
                type="text"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-8 pr-4 py-2 text-sm border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white"
                placeholder="Rechercher..."
              />
              <i className="fas fa-search absolute left-2.5 top-1/2 transform -translate-y-1/2 text-gray-400 text-xs"></i>
            </div>
            
            <select
              value={dateFilter}
              onChange={(e) => setDateFilter(e.target.value)}
              className="px-3 py-2 text-sm border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white"
            >
              <option value="Tous">Toutes dates</option>
              <option value="today">Aujourd'hui</option>
              <option value="week">Cette semaine</option>
              <option value="month">Ce mois</option>
            </select>
          </div>
        </div>
      </div>

      {/* Contenu des onglets */}
      <div className="p-6 overflow-y-auto" style={{ maxHeight: 'calc(100vh - 350px)' }}>
        {activeTab === 'tree' ? (
          <TreeView searchTerm={searchTerm} dateFilter={dateFilter} />
        ) : (
          <CategoryView searchTerm={searchTerm} dateFilter={dateFilter} />
        )}
      </div>
    </div>
  );
};

export default EditorialFlow;
